'use client';

import React from 'react';
import { motion } from 'framer-motion';
import { useAuth } from '@/lib/AuthContext';
import { MOCK_PROJECTS, MOCK_IMPACT_SCORES, MOCK_ACTIVITIES, SDG_INFO } from '@/data/mockData';
import ImpactGauge from '@/components/ui/ImpactGauge';
import SDGBarChart from '@/components/ui/SDGBarChart';
import AnimatedCounter from '@/components/ui/AnimatedCounter';
import Link from 'next/link';

const fadeIn = (delay: number) => ({
    initial: { opacity: 0, y: 20 },
    animate: { opacity: 1, y: 0 },
    transition: { duration: 0.5, delay },
});

export default function NGODashboard() {
    const { user } = useAuth();
    const myProjects = MOCK_PROJECTS.filter(p => p.organization_id === user?.id);
    const allProjects = myProjects.length > 0 ? myProjects : MOCK_PROJECTS.filter(p => p.organization_id === 'u1');
    const impactData = MOCK_IMPACT_SCORES.find(s => s.organization_id === (user?.id || 'u1'));
    const totalBeneficiaries = allProjects.reduce((s, p) => s + p.beneficiary_count, 0);
    const totalBudget = allProjects.reduce((s, p) => s + p.budget, 0);
    const totalSpent = allProjects.reduce((s, p) => s + p.spent, 0);
    const recentActivities = MOCK_ACTIVITIES.slice(0, 4);

    return (
        <div className="space-y-6">
            {/* Header */}
            <motion.div {...fadeIn(0)}>
                <h1 className="text-2xl font-bold text-white">Welcome back, <span className="gradient-text-cyan">{user?.name}</span></h1>
                <p className="text-sm text-gray-500 mt-1">{user?.organization_name} • NGO Dashboard</p>
            </motion.div>

            {/* Stat Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                {[
                    { label: 'Active Projects', value: allProjects.length, icon: '📁', color: '#06b6d4' },
                    { label: 'Total Beneficiaries', value: totalBeneficiaries, icon: '👥', color: '#10b981' },
                    { label: 'Budget Utilized', value: Math.round((totalSpent / totalBudget) * 100), icon: '💰', color: '#f59e0b', suffix: '%' },
                    { label: 'Impact Score', value: impactData?.overall_score || 847, icon: '⚡', color: '#8b5cf6' },
                ].map((stat, i) => (
                    <motion.div key={i} {...fadeIn(0.1 * (i + 1))} className="glass-card p-5">
                        <div className="flex items-center justify-between mb-3">
                            <span className="text-2xl">{stat.icon}</span>
                            <span className="text-xs px-2 py-1 rounded-lg" style={{ background: stat.color + '15', color: stat.color }}>
                                {stat.label}
                            </span>
                        </div>
                        <div className="text-3xl font-bold text-white">
                            <AnimatedCounter target={stat.value} suffix={stat.suffix} />
                        </div>
                    </motion.div>
                ))}
            </div>

            {/* Impact Score + SDG Breakdown */}
            <div className="grid md:grid-cols-2 gap-5">
                <motion.div {...fadeIn(0.3)} className="glass-card p-6">
                    <h2 className="text-lg font-semibold text-white mb-4">Organization Impact Score</h2>
                    <div className="flex items-center justify-around">
                        <ImpactGauge score={impactData?.overall_score || 847} />
                        <div className="space-y-3">
                            {[
                                { label: 'Beneficiary Scale', score: impactData?.beneficiary_scale || 88, color: '#06b6d4' },
                                { label: 'Outcome', score: impactData?.outcome_score || 85, color: '#10b981' },
                                { label: 'Geographic Need', score: impactData?.geographic_need || 82, color: '#8b5cf6' },
                                { label: 'Funding Efficiency', score: impactData?.funding_efficiency || 79, color: '#f59e0b' },
                                { label: 'Verification', score: impactData?.verification_score || 92, color: '#f43f5e' },
                            ].map((item, i) => (
                                <div key={i}>
                                    <div className="flex justify-between text-xs mb-1">
                                        <span className="text-gray-400">{item.label}</span>
                                        <span style={{ color: item.color }}>{item.score}%</span>
                                    </div>
                                    <div className="h-1.5 bg-white/5 rounded-full overflow-hidden w-40">
                                        <div className="h-full rounded-full progress-bar-animated"
                                            style={{ width: `${item.score}%`, background: item.color }} />
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                    <div className="mt-4 text-center">
                        <p className="text-xs text-gray-500">Impact per ₹1 Lakh: <span className="text-cyan-400 font-bold">
                            {Math.round(totalBeneficiaries / (totalBudget / 100000))} lives</span></p>
                    </div>
                </motion.div>

                <motion.div {...fadeIn(0.4)} className="glass-card p-6">
                    <h2 className="text-lg font-semibold text-white mb-4">SDG-wise Breakdown</h2>
                    <SDGBarChart data={impactData?.sdg_breakdown || []} />
                </motion.div>
            </div>

            {/* Projects List */}
            <motion.div {...fadeIn(0.5)} className="glass-card p-6">
                <div className="flex items-center justify-between mb-4">
                    <h2 className="text-lg font-semibold text-white">Your Projects</h2>
                    <Link href="/dashboard/ngo/create-project" className="btn-neon text-xs px-4 py-2 no-underline">
                        + Create Project
                    </Link>
                </div>
                <div className="space-y-3">
                    {allProjects.map((project) => (
                        <div key={project.id} className="p-4 rounded-xl transition-all hover:bg-white/5"
                            style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.05)' }}>
                            <div className="flex items-center justify-between">
                                <div className="flex-1">
                                    <h3 className="text-sm font-semibold text-white">{project.title}</h3>
                                    <p className="text-xs text-gray-500 mt-1">{project.location.name} • {project.beneficiary_count.toLocaleString()} beneficiaries</p>
                                </div>
                                <div className="flex items-center gap-2">
                                    {project.sdg_tags.map(tag => (
                                        <span key={tag} className={`sdg-${tag} text-xs px-2 py-0.5 rounded-md font-medium`}>
                                            SDG {tag}
                                        </span>
                                    ))}
                                    <span className="text-xs px-2 py-1 rounded-lg ml-2"
                                        style={{
                                            background: project.status === 'active' ? 'rgba(16,185,129,0.1)' : 'rgba(245,158,11,0.1)',
                                            color: project.status === 'active' ? '#10b981' : '#f59e0b',
                                        }}>
                                        {project.status}
                                    </span>
                                </div>
                            </div>
                            {/* Budget progress */}
                            <div className="mt-3">
                                <div className="flex justify-between text-xs text-gray-500 mb-1">
                                    <span>₹{(project.spent / 100000).toFixed(1)}L spent</span>
                                    <span>₹{(project.budget / 100000).toFixed(1)}L budget</span>
                                </div>
                                <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
                                    <div className="h-full bg-cyan-500 rounded-full progress-bar-animated"
                                        style={{ width: `${(project.spent / project.budget) * 100}%` }} />
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </motion.div>

            {/* Recent Activities */}
            <motion.div {...fadeIn(0.6)} className="glass-card p-6">
                <div className="flex items-center justify-between mb-4">
                    <h2 className="text-lg font-semibold text-white">Recent Activities</h2>
                    <Link href="/dashboard/ledger" className="text-xs text-cyan-400 hover:underline">View All →</Link>
                </div>
                <div className="space-y-3">
                    {recentActivities.map(act => (
                        <div key={act.id} className="flex items-start gap-3 p-3 rounded-lg hover:bg-white/3 transition"
                            style={{ background: 'rgba(255,255,255,0.02)' }}>
                            <div className="w-8 h-8 rounded-lg flex items-center justify-center text-sm flex-shrink-0"
                                style={{ background: act.verified ? 'rgba(16,185,129,0.15)' : 'rgba(245,158,11,0.15)' }}>
                                {act.verified ? '✓' : '⏳'}
                            </div>
                            <div className="flex-1 min-w-0">
                                <p className="text-sm text-white">{act.description}</p>
                                <p className="text-xs text-gray-500 mt-1">{act.location} • {new Date(act.timestamp).toLocaleDateString()}</p>
                            </div>
                            <code className="text-[10px] text-gray-600 font-mono">{act.hash.slice(0, 12)}...</code>
                        </div>
                    ))}
                </div>
            </motion.div>
        </div>
    );
}
